INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('988227e3-4aba-5df4-b2be-0b65e2b8b2de', 'education-islamique-3eme', 'سورتا الليل والشمس', 'نحفظ سورتَي الليل (21 آية) والشمس (15 آية)، فيقسم الله بالليل والنهار والشمس والقمر، ونتعلّم أنّ من أعطى واتّقى ييسّره الله لليُسرى، وأنّ من زكّى نفسه أفلح', '# 📖 سورتا الليل والشمس — قَسَمُ اللهِ بآياتِ الكون

> 💡 «أقسمَ اللهُ بالليلِ والنهارِ والشمسِ والقمرِ، ليُعلّمنا أنّ الخيرَ طريقٌ سهل، وأنّ مَن زكّى نفسَه فقد فاز.»

كلتا السورتين **مكّيّةٌ** من **القرآن الكريم**، نزلتا على النبيّ محمّد ﷺ في مكّة. سورة **الليل** فيها **21** آية، وسورة **الشمس** فيها **15** آية. تعالَ نتعلّمهما معًا!

## 🌙 سورة الليل

عددُ آياتها **21** آية. نبدأ تلاوتها هكذا:

وَاللَّيْلِ إِذَا يَغْشَىٰ

وَالنَّهَارِ إِذَا تَجَلَّىٰ

وَمَا خَلَقَ الذَّكَرَ وَالْأُنثَىٰ

إِنَّ سَعْيَكُمْ لَشَتَّىٰ

فَأَمَّا مَنْ أَعْطَىٰ وَاتَّقَىٰ

وَصَدَّقَ بِالْحُسْنَىٰ

في هذه السورة **أقسمَ اللهُ** بالليلِ حين يُغطّي الدنيا بظلامه، وبالنهارِ حين يظهر بنوره، وبخلقه الذكرَ والأنثى. ثمّ أخبرنا أنّ **أعمالَ الناسِ مختلفة** («لَشَتَّىٰ»)، فالناسُ قِسمان:

- **قِسمٌ أعطى واتّقى** وصدّق بالخير: هذا **ييسّره الله لليُسرى**، أي يُسهّل له طريقَ الخيرِ والجنّة.
- **قِسمٌ بخِلَ واستغنى** وكذّب بالخير: هذا يُيسّره الله **للعُسرى**، أي طريقِ الصعوبةِ بسبب بُخله.

فالعطاءُ والتقوى يفتحان أبوابَ الخير، والبُخلُ يُغلقها. ونتعلّم من السورة أن نكون **كُرماءَ أتقياء** نُحبّ الخير ونعمله.

## ☀️ سورة الشمس

عددُ آياتها **15** آية. نبدأ تلاوتها هكذا:

وَالشَّمْسِ وَضُحَاهَا

وَالْقَمَرِ إِذَا تَلَاهَا

وَالنَّهَارِ إِذَا جَلَّاهَا

وَاللَّيْلِ إِذَا يَغْشَاهَا

وَالسَّمَاءِ وَمَا بَنَاهَا

وَالْأَرْضِ وَمَا طَحَاهَا

هنا **أقسمَ اللهُ** بمخلوقاتٍ عظيمة: **الشمسِ** وضوئها، و**القمرِ** الذي يأتي بعدها، و**النهارِ** و**الليلِ**، و**السماءِ** و**الأرضِ**، وبالنفسِ التي خلقها وسوّاها. ثمّ علّمنا قاعدةً كبيرة:

**قَدْ أَفْلَحَ مَن زَكَّاهَا** — فاز مَن **طهّر نفسَه** بالخير والطاعة، **وَقَدْ خَابَ مَن دَسَّاهَا** — خسِر مَن أفسد نفسَه بالشرّ.

ثمّ ضربَ الله لنا **مثلًا** من التاريخ: قومُ **ثمود** كذّبوا نبيّهم **صالحًا** عليه السلام بسبب طغيانهم. أرسل الله إليهم **ناقةً** آيةً، وقال لهم نبيُّهم: احذروا أن تُؤذوها واتركوها تشرب. لكنّ أشقاهم **عقرَ الناقة**، فعصَوا ربّهم، فعاقبهم الله جميعًا. ونتعلّم من قصّتهم ألّا نطغى ولا نُكذّب، وأن نُطيع الله ورسوله.

> 🗝️ تذكّر الفرق: سورة **الليل** تبدأ بـ **وَاللَّيْلِ إِذَا يَغْشَىٰ**، وسورة **الشمس** تبدأ بـ **وَالشَّمْسِ وَضُحَاهَا**. أوّلُ كلمةٍ تدلّك على اسم السورة.

> 🏆 أحسنت أيّها البطل! حفظتَ سورتَي الليل والشمس وفهمتَ معناهما. في الفصل القادم نتعلّم **الوضوءَ والتيمّمَ** لنتطهّر قبل الصلاة.', '# 📜 ملخّص: سورتا الليل والشمس

- **سورتان مكّيّتان** من القرآن الكريم: سورة الليل فيها 21 آية، وسورة الشمس فيها 15 آية.
- **سورة الليل** تبدأ بـ: وَاللَّيْلِ إِذَا يَغْشَىٰ، فأقسم الله بالليل والنهار وخلق الذكر والأنثى.
- **أعمال الناس مختلفة** (إِنَّ سَعْيَكُمْ لَشَتَّىٰ): فالناس قسمان في سورة الليل.
- **مَن أعطى واتّقى** وصدّق بالحُسنى: ييسّره الله لليُسرى، أي طريق الخير.
- **مَن بخِل واستغنى** وكذّب: يُيسّره الله للعُسرى، أي طريق الصعوبة.
- **سورة الشمس** تبدأ بـ: وَالشَّمْسِ وَضُحَاهَا، فأقسم الله بالشمس والقمر والنهار والليل والسماء والأرض والنفس.
- **قَدْ أَفْلَحَ مَن زَكَّاهَا**: فاز مَن طهّر نفسه بالخير والطاعة.
- **وَقَدْ خَابَ مَن دَسَّاهَا**: خسِر مَن أفسد نفسه بالشرّ.
- **قوم ثمود** كذّبوا نبيّهم صالحًا عليه السلام بسبب طغيانهم.
- **الناقة**: آية أرسلها الله لثمود، فعقرها أشقاهم فعصَوا ربّهم فعاقبهم الله.
- **العِبرة**: نكون كُرماءَ أتقياء، نزكّي أنفسنا بالخير، ولا نطغى ولا نُكذّب.', 5)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('0b15d03b-95d5-5431-8ed9-9ea908eef231', 'education-islamique-3eme', 'الوضوء والتيمّم', 'نتعلّم الوضوء: تعريفَه وفرائضَه وسننَه وكيف نؤدّيه عمليًّا، ثمّ نتعرّف على التيمّم ومتى نلجأ إليه عند فقد الماء أو العجز عن استعماله', '# 💧 الوضوء والتيمّم — سلاحُ الطهارةِ قبل الصلاة

> 💡 «قبل أن نقف بين يدَيِ الله في الصلاة، نتطهّر بالماء، فيصير قلبُنا وجسمُنا نظيفَين.»

## 🌊 ما هو الوضوء؟

الوضوءُ هو **طهارةٌ مائيّةٌ** تكون **قبل الصلاة** بماءٍ **طَهور** (ماءٍ نظيفٍ كماء البحار والأنهار والآبار والمطر). نتوضّأ لِنُصلّيَ ونحن طاهرون.

> 🗡️ الوضوءُ مِفتاحُ الصلاة: لا تصحّ صلاتُنا إلّا إذا توضّأنا أوّلًا!

## ⚔️ فرائضُ الوضوء

الفرائضُ هي الأركانُ التي **لا بدّ منها**، إذا تركنا واحدةً منها لم يصحّ الوضوء. وهي سبعةٌ بالترتيب:

| الرقم | الفريضة |
| --- | --- |
| 1 | النيّة |
| 2 | غسل الوجه |
| 3 | غسل اليدين إلى المرفقين |
| 4 | مسح الرأس |
| 5 | غسل الرجلين إلى الكعبين |
| 6 | الفور (الموالاة: نتابع دون انقطاعٍ طويل) |
| 7 | التدليك (نَدلُك العضوَ بيدنا) |

## 🌟 سننُ الوضوء

السننُ نفعلها اقتداءً بالنبيّ ﷺ، فيها أجرٌ كبير، لكنّ الوضوء يصحّ بدونها. وأشهرُها:

| الرقم | السُّنّة |
| --- | --- |
| 1 | غسل اليدين إلى الرسغين أوّلًا ثلاث مرات |
| 2 | المضمضة ثلاث مرات |
| 3 | الاستنشاق ثلاث مرات |
| 4 | الاستنثار ثلاث مرات |
| 5 | مسح الأذنين ظاهرهما وباطنهما |
| 6 | ردّ مسح الرأس |
| 7 | ترتيب فرائض الوضوء |

## 🔥 كيف نتوضّأ عمليًّا؟

نتوضّأ بالترتيب خطوةً خطوة، هكذا علّمنا النبيّ ﷺ:

1. نغسل **اليدين إلى الكوعين 3 مرات**.
2. **المضمضة 3 مرات** (نُدخل الماء إلى الفم).
3. **الاستنشاق والاستنثار 3 مرات** (نُدخل الماء إلى الأنف ثمّ نُخرجه).
4. نغسل **الوجه 3 مرات**.
5. نغسل **اليدين إلى المرفقين** (اليمنى ثمّ اليسرى).
6. **نمسح الرأس** بأيدينا المبلّلة.
7. **نمسح الأذنين مرّةً واحدة**.
8. نغسل **الرجلين إلى الكعبين** (اليمنى ثمّ اليسرى).

> ✨ الكعبُ هو العظمُ الناتئُ في الرِّجل، والمرفقُ هو مَفصلُ اليد. نغسل إليهما حتّى يكون الوضوءُ كاملًا.

## 🏜️ التيمّم — طهارةٌ بالتراب

أحيانًا **لا نجد الماء**، أو نجده ولا نستطيع استعماله (كمريضٍ يضرّه الماء). عندئذٍ نتطهّر بـ**التيمّم**، وهو **طهارةٌ ترابيّةٌ** بالصَّعيد الطاهر (التراب النظيف).

نُتمّ التيمّم هكذا: نَنوي بقلبنا، ثمّ نقوم بهذه الحركات:

1. **نضرب اليدين على الصَّعيد** (التراب الطاهر) — الضربةُ الأولى.
2. **نمسح الوجه** مسحًا خفيفًا.
3. **نمسح اليدين إلى المرفقين** (اليمنى ثمّ اليسرى).

> ⚠️ التيمّمُ بديلٌ عن الوضوء فقط **عند فقد الماء أو العجز عن استعماله**. فإذا وجدنا الماء وقدِرنا عليه عُدنا إلى الوضوء.

> 🏆 أحسنت أيّها البطل! تطهّرتَ بالماء وبالتراب وصِرتَ مستعدًّا. في الفصل القادم نتعلّم **الصلاة** نفسها، فنقف بين يدَيِ الله طاهرين.', '# 📜 ملخّص: الوضوء والتيمّم

- **الوضوء**: طهارةٌ مائيّةٌ تكون قبل الصلاة بماءٍ طَهور (نظيف).
- الوضوءُ شرطٌ لصحّة الصلاة: لا نُصلّي إلّا متطهّرين.
- **فرائض الوضوء** (سبعة): النيّة، غسل الوجه، غسل اليدين إلى المرفقين، مسح الرأس، غسل الرجلين إلى الكعبين، الفور، التدليك.
- إذا تركنا فريضةً واحدة لم يصحّ الوضوء.
- **سنن الوضوء**: غسل اليدين إلى الرسغين أوّلًا، المضمضة، الاستنشاق، الاستنثار، مسح الأذنين، ردّ مسح الرأس، الترتيب — وفيها أجرٌ والوضوءُ يصحّ بدونها.
- **الأداء العملي**: غسل اليدين إلى الكوعين 3 مرات، ثمّ المضمضة 3 مرات، ثمّ الاستنشاق والاستنثار 3 مرات.
- ثمّ غسل الوجه 3 مرات، فغسل اليدين إلى المرفقين، فمسح الرأس.
- ثمّ مسح الأذنين مرّةً واحدة، وأخيرًا غسل الرجلين إلى الكعبين.
- **التيمّم**: طهارةٌ ترابيّةٌ بالصَّعيد الطاهر، نلجأ إليه عند فقد الماء أو العجز عن استعماله.
- **حركات التيمّم**: النيّة، ثمّ ضرب اليدين على الصَّعيد، فمسح الوجه، فمسح اليدين إلى المرفقين.
- إذا وجدنا الماء وقدِرنا عليه عُدنا إلى الوضوء.', 6)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('fe745984-00ee-55ee-8571-68f9931f0b0d', 'education-islamique-3eme', 'الصلاة', 'نتعرّف على الصلوات الخمس ومواقيتها، ونتعلّم مكوّنات الركعة وأذكارها بالترتيب، وكيف نؤدّي الصلاة عمليًّا مع لفظ التشهّد ودعاء القنوت', '# 🕌 الصلاة — لقاءُ العبدِ بربّهِ خمسَ مرّاتٍ في اليوم

> 💡 «الصلاةُ عمودُ الدين، نقف فيها بين يدَيِ الله خاشعين، فنُناجيه ونحمده ونسجد له.»

## 🌟 ما هي الصلاة؟

الصلاةُ عبادةٌ عظيمةٌ نؤدّيها **خمسَ مرّاتٍ في اليوم والليلة**، كلٌّ منها في **وقتها** الذي حدّده الله. نتطهّر بالوضوء أوّلًا، ثمّ نستقبل القبلة ونقف بين يدَيِ الله.

> 🗡️ الصلاةُ كنزُ المسلم: من حافظ على صلواته الخمس فقد أمسك بأقوى سلاحٍ يقرّبه من ربّه.

## ⏰ الصلواتُ الخمسُ ومواقيتها

نُصلّي 5 صلواتٍ كلَّ يوم، ولكلِّ صلاةٍ **وقتٌ** نعرفه من حال الشمس، ولكلِّ صلاةٍ **عددُ ركعاتٍ**:

| الصلاة | وقتها (نعرفه هكذا) | عدد الركعات |
| --- | --- | --- |
| **الصبح** | من طلوع الفجر إلى ما قبل بزوغ الشمس | 2 |
| **الظهر** | بعد زوال الشمس (إذا مالت عن وسط السماء) | 4 |
| **العصر** | عند اصفرار الشمس قبل الغروب | 4 |
| **المغرب** | بعد غروب الشمس | 3 |
| **العشاء** | بعد مغيب الشفق الأحمر إلى الفجر | 4 |

> ✨ صلاةُ الصبح **جهريّة** (نقرأ فيها بصوتٍ مسموع)، وصلاتا الظهر والعصر **سرّيّتان** (نقرأ فيهما في أنفسنا).

## ⚔️ مكوّناتُ الركعةِ بالترتيب

الركعةُ هي **وحدةُ الصلاة**، نؤدّيها خطوةً خطوة كما علّمنا النبيُّ ﷺ. هذا ترتيبُها وأذكارُها:

1. **تكبيرةُ الإحرام**: نقول **«الله أكبر»** ونرفع اليدين إلى جانبَيِ الرأس. بها **ندخل** في الصلاة.
2. **قراءةُ الفاتحة**: نقرأ سورة الفاتحة وقوفًا.
3. **الركوع**: ننحني فيصير الظهرُ مستويًا واليدان على الرُّكبتين، ونقول: **«سبحان ربّي العظيم» ثلاث مرات**.
4. **الرفعُ من الركوع**: نعتدل واقفين ونقول: **«سمع الله لمن حمده، ربّنا ولك الحمد»**.
5. **السجودُ الأوّل**: نضع جبهتنا على الأرض، ونقول: **«سبحان ربّي الأعلى» ثلاث مرات**.
6. **الرفعُ من السجود الأوّل**: نجلس ونقول: **«الله أكبر»**.
7. **السجودُ الثاني**: نسجد مرّةً أخرى ونقول: **«سبحان ربّي الأعلى» ثلاث مرات**، ثمّ ننهض للركعة التالية ونقول: **«الله أكبر»**.

> 🔥 لاحظ البطل: نقول **«سبحان ربّي العظيم»** في **الركوع**، و**«سبحان ربّي الأعلى»** في **السجود**. لا تخلط بينهما!

## 🔮 كيف نُتمّ الصلاة؟ (الركعة الثانية والسلام)

بعد السجود الثاني نقف للركعة الثانية ونعيد المكوّنات نفسها. وفي آخر الصلاة **نجلس** ونقرأ **التشهّد**، ثمّ نُنهي الصلاة بـ**السلام**: نقول **«السلام عليكم»** ونلتفت بوجهنا إلى **اليمين** ثمّ إلى **اليسار**.

## 📜 لفظُ التشهّد

في جلوس آخر الصلاة نقرأ التشهّد، وهذا لفظُه:

> 🕌 التحيّاتُ لله، الزاكياتُ لله، الطيّباتُ الصلواتُ لله، السلامُ عليك أيّها النبيُّ ورحمةُ الله وبركاتُه، السلامُ علينا وعلى عباد الله الصالحين، أشهد أن لا إله إلّا الله وحده لا شريك له، وأشهد أنّ محمّدًا عبده ورسوله.

## 🤲 دعاءُ القنوت

في **صلاة الصبح**، في **الركعة الثانية قبل الركوع**، ندعو بدعاء القنوت، وهذا أوّلُه:

> 🌟 اللهمّ إنّا نستعينك ونستغفرك ونؤمن بك ونتوكّل عليك ونثني عليك الخير كلّه، نشكرك ولا نكفرك...

> 🏆 أحسنت أيّها البطل! تعلّمتَ كيف تقف بين يدَيِ الله وتُتمّ صلاتك. في الفصل القادم نتعرّف على **صلاة الجمعة وصلاة العيدين** — صلواتٍ نجتمع لها مع المسلمين.', '# 📜 ملخّص: الصلاة

- **الصلاة** عبادةٌ نؤدّيها 5 مرّاتٍ في اليوم والليلة، كلٌّ في وقتها بعد الوضوء واستقبال القبلة.
- **الصلوات الخمس**: الصبح (2 ركعتان)، الظهر (4 ركعات)، العصر (4 ركعات)، المغرب (3 ركعات)، العشاء (4 ركعات).
- نعرف **الأوقات** من حال الشمس: الصبح من طلوع الفجر، الظهر بعد زوال الشمس، العصر عند اصفرارها، المغرب بعد غروبها، العشاء بعد مغيب الشفق الأحمر.
- صلاةُ الصبح **جهريّة**، وصلاتا الظهر والعصر **سرّيّتان**.
- **مكوّنات الركعة بالترتيب**: تكبيرة الإحرام، ثمّ قراءة الفاتحة، ثمّ الركوع، ثمّ الرفع منه، ثمّ السجود الأوّل، ثمّ الرفع منه، ثمّ السجود الثاني.
- **تكبيرة الإحرام**: نقول «الله أكبر» ونرفع اليدين، وبها ندخل في الصلاة.
- في **الركوع** نقول: «سبحان ربّي العظيم» 3 مرات، وعند **الرفع منه**: «سمع الله لمن حمده، ربّنا ولك الحمد».
- في **السجود** نقول: «سبحان ربّي الأعلى» 3 مرات، وعند الرفع والانتقال نقول: «الله أكبر».
- في آخر الصلاة نجلس ونقرأ **التشهّد**: التحيّاتُ لله... أشهد أن لا إله إلّا الله... وأشهد أنّ محمّدًا عبده ورسوله.
- نُنهي الصلاة بـ**السلام**: «السلام عليكم» التفاتًا يمينًا ثمّ يسارًا.
- **دعاء القنوت** يكون في صلاة الصبح، في الركعة الثانية قبل الركوع: «اللهمّ إنّا نستعينك ونستغفرك...».', 7)
ON CONFLICT (id) DO UPDATE SET
