INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8aa6b11-2447-59d3-8289-9f186aa6132e', 'bf4d9698-af40-5f03-accb-3d72cb5cd2b5', 'أرادَ تلميذٌ أن يقرأ سورة الإخلاص. ما أوّلُ ما يقوله؟', '[{"id":"a","text":"أعوذ بالله من الشيطان الرجيم"},{"id":"b","text":"قل هو الله أحد مباشرة"},{"id":"c","text":"بسم الله الرحمن الرحيم ثمّ الآيات"},{"id":"d","text":"الحمد لله ربّ العالمين"}]'::jsonb, 'a', 'نبدأ التلاوة بالاستعاذة أوّلًا (أعوذ بالله من الشيطان الرجيم)، ثمّ البَسملة، ثمّ الآيات. فأوّل ما يقوله هو الاستعاذة.', 1)
