INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('01d90d62-27c2-57f7-87c4-94125e9e990a', 'bf4d9698-af40-5f03-accb-3d72cb5cd2b5', 'تلميذٌ بدأ بالاستعاذة ثمّ قرأ الآيات ونسي البَسملة في أوّل سورةٍ غير التوبة. ماذا نقول؟', '[{"id":"a","text":"فعل الصواب تمامًا"},{"id":"b","text":"نسي البَسملة التي تكون في أوّل السورة"},{"id":"c","text":"نسي الاستعاذة"},{"id":"d","text":"البَسملة لا تُقرأ أصلًا"}]'::jsonb, 'b', 'البَسملة تُقرأ في أوّل كلّ سورةٍ إلّا التوبة، فالتلميذ نسيَها. الخطأ الشائع ظنّ أنّ الاستعاذة وحدها تكفي.', 2)
