INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf21451e-2851-569e-b996-268794202325', 'be81ee36-88d0-5517-ab0c-b26267d5b6ea', 'معنى «رفَع الله ذِكر نبيّه ﷺ» أنّه ...', '[{"id":"a","text":"أخفى اسمه"},{"id":"b","text":"جعل اسمه عاليًا مذكورًا في كلّ مكان"},{"id":"c","text":"نسيَ اسمه الناس"},{"id":"d","text":"غيّر اسمه"}]'::jsonb, 'b', 'رفَع الله ذِكره أي جعل اسم النبيِّ ﷺ عاليًا مذكورًا في كلّ مكان، كما في الشهادة والأذان.', 3)
