INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0c2949d2-6dca-538b-ad68-f15640adf0f4', 'be81ee36-88d0-5517-ab0c-b26267d5b6ea', 'ماذا نفعل عندما نواجه أمرًا صعبًا، كما تُعلّمنا السورة؟', '[{"id":"a","text":"نصبر وندعو ربّنا فالفرَج قريب"},{"id":"b","text":"نحزن ونستسلم"},{"id":"c","text":"نتركه ونهرب"},{"id":"d","text":"نغضب على الناس"}]'::jsonb, 'a', 'تُعلّمنا السورة أنّ مع كلّ عُسرٍ يُسرًا، فنصبر وندعو ربّنا ولا نحزن، فالفرَج قريب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e51e2e51-50a7-51d7-8e25-c6b35138d8dc', 'be81ee36-88d0-5517-ab0c-b26267d5b6ea', '«وَإِلَىٰ رَبِّكَ فَٱرْغَب» تعني أن نرفع دعاءنا ورغبتنا إلى ...', '[{"id":"a","text":"الأصحاب"},{"id":"b","text":"أنفسنا"},{"id":"c","text":"الناس"},{"id":"d","text":"الله وحده"}]'::jsonb, 'd', 'وإلى ربّك فٱرغب أي ارفع رغبتك ودعاءك إلى الله وحده، فهو الذي يُعطي ويُجيب.', 5)
ON CONFLICT (id) DO UPDATE SET
