INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91d9f582-aa36-5e8d-8e85-b95e78a331fe', 'be81ee36-88d0-5517-ab0c-b26267d5b6ea', 'كم مرّةً ذكر الله «مع العُسرِ يُسرًا» في سورة الشرح؟', '[{"id":"a","text":"لم تُذكر أبدًا"},{"id":"b","text":"مرّتين"},{"id":"c","text":"خمس مرّات"},{"id":"d","text":"عشر مرّات"}]'::jsonb, 'b', 'ذكرها الله مرّتين متتاليتين ليُثبّت البُشرى في قلوبنا، فنطمئنّ أنّ بعد كلّ صعوبةٍ سهولة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a2636296-c59b-5d08-8b28-01cb4d77c4bc', 'e93653c4-bde5-5d7d-b235-23f834f59f3d', 'education-islamique-3eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ سورة الشرح', 4, 300, 60, 'challenge', 'admin', 4)
