INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e0f8c21c-f2d9-5940-84af-62045f5641f2', 'a2636296-c59b-5d08-8b28-01cb4d77c4bc', 'رتّب آيات سورة الشرح: (1) وَرَفَعْنَا لَكَ ذِكْرَكَ (2) أَلَمْ نَشْرَحْ لَكَ صَدْرَكَ (3) وَوَضَعْنَا عَنكَ وِزْرَكَ. ما الترتيب الصحيح من أوّلها؟', '[{"id":"a","text":"1 ثمّ 2 ثمّ 3"},{"id":"b","text":"2 ثمّ 3 ثمّ 1"},{"id":"c","text":"3 ثمّ 1 ثمّ 2"},{"id":"d","text":"1 ثمّ 3 ثمّ 2"}]'::jsonb, 'b', 'تبدأ السورة بـ«أَلَمْ نَشْرَحْ لَكَ صَدْرَكَ» (2) ثمّ «وَوَضَعْنَا عَنكَ وِزْرَكَ» (3) ثمّ بعد آيةٍ «وَرَفَعْنَا لَكَ ذِكْرَكَ» (1). الخطأ الشائع تقديم آية رفع الذِّكر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ffd743fd-4fe3-57ec-a9a8-9e8980281fb0', 'a2636296-c59b-5d08-8b28-01cb4d77c4bc', 'قال تلميذٌ: «سورة الشرح تَعِدُنا بالمال والقصور عند الصعوبة». هل قوله صحيح؟', '[{"id":"a","text":"نعم، تَعِدُ بالمال"},{"id":"b","text":"نعم، تَعِدُ بالقصور"},{"id":"c","text":"لا، بل تَعِدُ بأنّ مع العُسرِ يُسرًا"},{"id":"d","text":"لا تَعِدُ بشيء"}]'::jsonb, 'c', 'السورة لا تَعِدُ بمالٍ ولا قصور، بل بُشراها أنّ مع كلّ عُسرٍ يُسرًا، أي بعد الصعوبة سهولة. الخطأ الشائع فهم اليُسر على أنّه مالٌ فقط.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58299b75-bd0f-59ce-87a7-8afc09185c8b', 'a2636296-c59b-5d08-8b28-01cb4d77c4bc', '«فَإِذَا فَرَغْتَ فَٱنصَبْ»: تلميذٌ أنهى واجبه فجلس يلعب طوال اليوم. ماذا نقول له على ضوء الآية؟', '[{"id":"a","text":"أحسنت، هذا هو المطلوب"},{"id":"b","text":"الآية تأمر باللعب"},{"id":"c","text":"لا فرق في ذلك"},{"id":"d","text":"بعد الفراغ نجتهد في عملٍ صالحٍ آخر لا نكسل"}]'::jsonb, 'd', 'فإذا فرغتَ فٱنصب أي إذا انتهيتَ من عملٍ فاجتهد في عملٍ صالحٍ آخر وفي العبادة، ولا تكسل. الخطأ الشائع فهم الفراغ على أنّه وقتٌ للكسل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21207073-b221-50cf-bf5d-70257504e4bd', 'a2636296-c59b-5d08-8b28-01cb4d77c4bc', 'لماذا أنزل الله سورة الشرح على نبيّه ﷺ؟', '[{"id":"a","text":"ليُطمئن قلبه ويُثبّته ويُبشّره"},{"id":"b","text":"ليأمره بالتجارة"},{"id":"c","text":"ليُعلّمه الحساب"},{"id":"d","text":"ليطلب منه مالًا"}]'::jsonb, 'a', 'أنزلها الله ليُطمئن قلب نبيّه ﷺ ويُثبّته، ويُبشّره بأنّ مع العُسرِ يُسرًا. الخطأ الشائع ربط السورة بأمورٍ ماديّة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4281b801-0fab-53d7-b7a5-3fe6ece56e79', 'a2636296-c59b-5d08-8b28-01cb4d77c4bc', 'أيُّ هذه المعاني يجمع رسالة سورة الشرح كلّها؟', '[{"id":"a","text":"اجمع المال ثمّ ارتح"},{"id":"b","text":"العب كثيرًا ولا تتعب"},{"id":"c","text":"اصبر عند العُسر، واجتهد، وارغب إلى ربّك"},{"id":"d","text":"اترك العمل عند الصعوبة"}]'::jsonb, 'c', 'تجمع السورة: البُشرى بأنّ مع العُسرِ يُسرًا (الصبر)، والأمر بالاجتهاد بعد الفراغ، والرغبة إلى الله وحده. الخطأ الشائع اختزالها في معنًى واحد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd1b4097-e62a-5e09-8626-7ec3f2c60ac6', 'a2636296-c59b-5d08-8b28-01cb4d77c4bc', '«وَإِلَىٰ رَبِّكَ فَٱرْغَب»: تلميذٌ يريد النجاح فطلبه من أصدقائه فقط ونسي الدعاء. ما الأصحّ على ضوء الآية؟', '[{"id":"a","text":"أن يرفع رغبته ودعاءه إلى الله وحده"},{"id":"b","text":"أن يطلب من الناس فقط"},{"id":"c","text":"أن يعتمد على نفسه فقط"},{"id":"d","text":"أن يترك النجاح"}]'::jsonb, 'a', 'وإلى ربّك فٱرغب أي ارفع رغبتك ودعاءك إلى الله وحده مع الأخذ بالأسباب، فهو الذي يُعطي ويُجيب. الخطأ الشائع نسيان الدعاء والاعتماد على الناس وحدهم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

