INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a18a00c9-d30f-5ba9-a1b3-2010fdfb6193', 'd1729199-0a77-5e79-abf3-93b5e8ffdde2', 'سورة الشرح نزلت في مكّة، فهي سورةٌ ...', '[{"id":"a","text":"مدنيّة"},{"id":"b","text":"طويلة"},{"id":"c","text":"مكّيّة"},{"id":"d","text":"من القصص"}]'::jsonb, 'c', 'السورة التي نزلت في مكّة تُسمّى مكّيّة، وسورة الشرح نزلت في مكّة فهي مكّيّة، عدد آياتها 8.', 1)
