INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f56eb92-a234-5adc-bb65-205546e3da74', 'd1729199-0a77-5e79-abf3-93b5e8ffdde2', 'من النِّعَم التي ذكرها الله في السورة أنّه «رفَع ذِكر» نبيّه ﷺ، أي ...', '[{"id":"a","text":"أخفى اسمه عن الناس"},{"id":"b","text":"جعل اسمه عاليًا مذكورًا في كلّ مكان"},{"id":"c","text":"أعطاه جبالًا"},{"id":"d","text":"غيّر اسمه"}]'::jsonb, 'b', 'رفَع الله ذِكره أي جعل اسم النبيِّ ﷺ عاليًا مذكورًا، كما نذكره في الشهادة والأذان والصلاة عليه.', 4)
