INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b1b2dd9-398c-5a35-bad3-9db2b3bfc870', '05ed3272-9919-563d-a28c-0d25d7f3b9e3', 'لماذا نزلت سورة الضحى على النبيّ ﷺ؟', '[{"id":"a","text":"لأنّ الناس فرحوا"},{"id":"b","text":"لتُطمئنه أنّ ربّه لم يتركه بعد تأخّرِ الوحي"},{"id":"c","text":"لأنّه سافر إلى المدينة"},{"id":"d","text":"لأنّه نسي الصلاة"}]'::jsonb, 'b', 'تأخّرَ الوحي مدّةً قصيرة فحزِنَ النبيّ ﷺ، فأنزل اللهُ السورةَ ليُطمئنه أنّ ربّه لم يتركه. الخطأ الشائع ظنُّ أنّها نزلت للفرح، وهي نزلت تطمينًا.', 1)
