INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7b5eb63-1098-51d8-88be-46c7a5b6897b', '05ed3272-9919-563d-a28c-0d25d7f3b9e3', 'معنى «وَاللَّيْلِ إِذَا سَجَىٰ» أنّ الليل ...', '[{"id":"a","text":"طلعت فيه الشمس"},{"id":"b","text":"نزل فيه المطر"},{"id":"c","text":"اشتدّ فيه الحرّ"},{"id":"d","text":"سكنَ وهدأ بظلامه"}]'::jsonb, 'd', 'سجى الليلُ أي سكنَ واستقرّ ظلامُه وهدأ. الخطأ الشائع ربطُ السجوّ بطلوع الشمس، وهو خاصٌّ بسكون الليل.', 2)
