INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ee03b60c-5d40-5268-9b86-8b2edd863cf8', '05ed3272-9919-563d-a28c-0d25d7f3b9e3', 'قال الله: «وَلَلْآخِرَةُ خَيْرٌ لَّكَ مِنَ الْأُولَىٰ». ما المقصود بـ«الأولى»؟', '[{"id":"a","text":"الحياةُ الدنيا"},{"id":"b","text":"أوّلُ سورةٍ في القرآن"},{"id":"c","text":"أوّلُ يومٍ في الأسبوع"},{"id":"d","text":"الصلاةُ الأولى"}]'::jsonb, 'a', '«الأولى» هي الحياةُ الدنيا، و«الآخرة» خيرٌ منها. الخطأ الشائع فهمُ «الأولى» على أنّها أوّلُ شيء، وهي هنا الدنيا.', 3)
