  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c50b40ce-0432-5242-be36-c26b675a50de', '05ed3272-9919-563d-a28c-0d25d7f3b9e3', 'ذكّرَ اللهُ نبيّه ﷺ: «أَلَمْ يَجِدْكَ يَتِيمًا فَآوَىٰ». ماذا فعل الله؟', '[{"id":"a","text":"تركه وحيدًا"},{"id":"b","text":"جعله غنيًّا فقط"},{"id":"c","text":"آواه وحفظه وهو يتيم"},{"id":"d","text":"أرسله إلى بلدٍ بعيد"}]'::jsonb, 'c', 'كان النبيّ ﷺ يتيمًا فآواه اللهُ وحفظه ورعاه. الخطأ الشائع الخلطُ بين الإيواء (الحفظ) والإغناء (المال).', 4)
