  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2fe51f2-9e66-57fb-81eb-4ff785821ff4', '6695ec6b-0c0f-57b9-b919-bf72b353d1a0', '«ووجدك ضالًّا فهدى»: ماذا فعل الله بنبيّه ﷺ؟', '[{"id":"a","text":"أبعده عن الناس"},{"id":"b","text":"هداه إلى طريق الحقّ"},{"id":"c","text":"أعطاه مالًا فقط"},{"id":"d","text":"تركه حائرًا"}]'::jsonb, 'b', 'هداه اللهُ إلى طريق الحقّ والإيمان والصواب، فدلّه على الخير.', 4)
