INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e8a3b350-ca76-51ea-9643-2389a338c7eb', '6695ec6b-0c0f-57b9-b919-bf72b353d1a0', '«فَأَمَّا الْيَتِيمَ فَلَا تَقْهَرْ» تأمرنا أن ...', '[{"id":"a","text":"نضحك على اليتيم"},{"id":"b","text":"نتركه جائعًا"},{"id":"c","text":"لا نظلم اليتيم بل نُحسن إليه"},{"id":"d","text":"نأخذ مالَه"}]'::jsonb, 'c', 'تأمرنا الآية ألّا نقهر اليتيم أو نظلمه، بل نُحسن إليه ونرحمه ونكرمه.', 5)
