INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65612f30-9b8e-5d6d-bfe9-89acfc574736', '6695ec6b-0c0f-57b9-b919-bf72b353d1a0', '«وَأَمَّا بِنِعْمَةِ رَبِّكَ فَحَدِّثْ» تعني أن ...', '[{"id":"a","text":"نتحدّث بنِعَمِ الله ونشكره عليها"},{"id":"b","text":"نُخفي كلّ نِعَم الله"},{"id":"c","text":"نشكو من كلّ شيء"},{"id":"d","text":"ننسى نِعَمَ الله"}]'::jsonb, 'a', 'تأمرنا الآية أن نتحدّث بنِعَمِ الله علينا ونشكره عليها، اعترافًا بفضله سبحانه.', 6)
