  ('acf3f279-508b-521a-b18b-e68b203b5880', 'fc923f36-b39c-5ae2-9302-32156dbb6a81', 'education-islamique-3eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ سورة الضحى', 4, 300, 60, 'challenge', 'admin', 4)
