INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc1d9680-38a9-5dd6-9946-48f7724f0446', 'acf3f279-508b-521a-b18b-e68b203b5880', 'صديقُك حزينٌ يظنّ أنّ اللهَ تركه. أيُّ آيةٍ من سورة الضحى تطمئنه؟', '[{"id":"a","text":"فَأَمَّا الْيَتِيمَ فَلَا تَقْهَرْ"},{"id":"b","text":"وَاللَّيْلِ إِذَا سَجَىٰ"},{"id":"c","text":"مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَىٰ"},{"id":"d","text":"وَأَمَّا السَّائِلَ فَلَا تَنْهَرْ"}]'::jsonb, 'c', '«مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَىٰ» تُطمئن أنّ اللهَ ما ترك عبده وما أبغضه. الخطأ الشائع اختيارُ آيةِ الأمرِ باليتيم، وهي لا تتحدّث عن التطمين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a30bcdcc-f5c2-5d66-a5cb-47fc0ff0477b', 'acf3f279-508b-521a-b18b-e68b203b5880', 'طفلٌ رأى سائلًا يطلب مساعدة فزجره بقسوة. أيَّ آيةٍ خالف؟', '[{"id":"a","text":"وَأَمَّا السَّائِلَ فَلَا تَنْهَرْ"},{"id":"b","text":"وَالضُّحَىٰ"},{"id":"c","text":"وَلَلْآخِرَةُ خَيْرٌ لَّكَ مِنَ الْأُولَىٰ"},{"id":"d","text":"وَوَجَدَكَ ضَالًّا فَهَدَىٰ"}]'::jsonb, 'a', 'خالفَ «وَأَمَّا السَّائِلَ فَلَا تَنْهَرْ» التي تنهى عن زجرِ السائل. الخطأ الشائع الخلطُ بين آيةِ السائل وآيةِ اليتيم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99e006ff-25a9-5d79-ac01-5f047624749a', 'acf3f279-508b-521a-b18b-e68b203b5880', 'قال الله: «وللآخرة خيرٌ لك من الأولى». ما الدرسُ الذي نأخذه؟', '[{"id":"a","text":"أنّ الدنيا أهمُّ من الآخرة"},{"id":"b","text":"أنّ الليلَ أطولُ من النهار"},{"id":"c","text":"أنّ السورةَ مدنيّة"},{"id":"d","text":"أنّ ما عند الله في الآخرة خيرٌ من الدنيا"}]'::jsonb, 'd', 'الدرسُ أنّ نعيمَ الآخرة عند الله خيرٌ وأبقى من الدنيا. الخطأ الشائع تفضيلُ الدنيا، والآية تُفضّل الآخرة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a58a5f6-8805-5f8e-85b1-7757a1bff936', 'acf3f279-508b-521a-b18b-e68b203b5880', 'رتّبَ تلميذٌ نِعَمَ الله هكذا: «هداه، ثمّ آواه، ثمّ أغناه». ما الصواب؟', '[{"id":"a","text":"ترتيبُه صحيحٌ تمامًا"},{"id":"b","text":"الصواب: آواه، ثمّ هداه، ثمّ أغناه"},{"id":"c","text":"الصواب: أغناه، ثمّ هداه، ثمّ آواه"},{"id":"d","text":"لا ترتيبَ للآيات"}]'::jsonb, 'b', 'ترتيبُ السورة: يتيمًا فآوى، ثمّ ضالًّا فهدى، ثمّ عائلًا فأغنى. الخطأ الشائع تقديمُ الهدايةِ على الإيواء.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b820750f-15e3-5705-bfb1-69ccbe42625d', 'acf3f279-508b-521a-b18b-e68b203b5880', 'نالَ تلميذٌ جائزةً، فأخبرَ أصدقاءه أنّها من فضلِ الله وشكره. أيَّ آيةٍ طبّق؟', '[{"id":"a","text":"وَأَمَّا بِنِعْمَةِ رَبِّكَ فَحَدِّثْ"},{"id":"b","text":"فَأَمَّا الْيَتِيمَ فَلَا تَقْهَرْ"},{"id":"c","text":"وَاللَّيْلِ إِذَا سَجَىٰ"},{"id":"d","text":"أَلَمْ يَجِدْكَ يَتِيمًا فَآوَىٰ"}]'::jsonb, 'a', 'طبّقَ «وَأَمَّا بِنِعْمَةِ رَبِّكَ فَحَدِّثْ» بأن تحدّثَ بنعمةِ الله وشكره. الخطأ الشائع اختيارُ آيةِ اليتيم، وهي في الإحسانِ لا في الشكر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd8f17ca-da43-5c72-b16d-b184690d4a95', 'acf3f279-508b-521a-b18b-e68b203b5880', 'ما الفكرةُ الجامعةُ التي تعلّمنا إيّاها سورة الضحى؟', '[{"id":"a","text":"أنّ الليلَ خيرٌ من النهار"},{"id":"b","text":"أنّ اليتيمَ لا يُساعَد"},{"id":"c","text":"أنّ الوحيَ لا ينقطع أبدًا لحظةً"},{"id":"d","text":"أنّ اللهَ لم يترك نبيّه ﷺ وأمره بالإحسان وشكرِ النعمة"}]'::jsonb, 'd', 'السورةُ تطمئن أنّ اللهَ لم يترك نبيّه ﷺ، وتأمر بالإحسانِ لليتيمِ والسائلِ والتحدّثِ بنعمةِ الله. الخطأ الشائع حصرُها في معنًى واحد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

