INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fcae14cc-f205-596b-8b49-8550c8b651de', '33ee23ad-d048-540c-8fc8-c9798079a969', 'ما سببُ نزولِ سورة الضحى؟', '[{"id":"a","text":"نزولُ المطرِ على مكّة"},{"id":"b","text":"تأخّرُ الوحي عن النبيّ ﷺ مدّةً قصيرة"},{"id":"c","text":"سفرُ النبيّ ﷺ إلى المدينة"},{"id":"d","text":"بناءُ مسجد"}]'::jsonb, 'b', 'تأخّرَ الوحي عن النبيّ ﷺ مدّةً قصيرة فحزِن، فنزلت السورةُ تُطمئنه أنّ ربّه لم يتركه.', 3)
