INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d1ab688-2af7-5ab1-b49a-b1b56a1081b0', '5dfbde04-78db-5ae7-9ef9-7921bf436cdd', 'قال الله: «لقد خلقنا الإنسان في أحسن تقويم». ما معنى ذلك؟', '[{"id":"a","text":"خلقه ضعيفًا لا يقدر على شيء"},{"id":"b","text":"خلقه في أحسن صورةٍ وأجملِ خِلقة"},{"id":"c","text":"خلقه مثل سائر الحيوانات"},{"id":"d","text":"خلقه ليعيش وحده دائمًا"}]'::jsonb, 'b', 'أحسن تقويم معناه أحسن صورةٍ وأجملِ خِلقة، فقد خلق الله الإنسان في أحسن هيئةٍ وأكملها.', 3)
