  ('552afb1a-e8ca-5d21-9dad-ae956fc4b5be', 'd40e5d29-33fd-5180-9dfb-0da97773aa38', 'ما الترتيب الصحيح لبدايات سورة التين؟', '[{"id":"a","text":"البلد الأمين ثمّ التين ثمّ طور سينين"},{"id":"b","text":"طور سينين ثمّ التين والزيتون"},{"id":"c","text":"التين والزيتون ثمّ طور سينين ثمّ البلد الأمين"},{"id":"d","text":"الإنسان ثمّ التين والزيتون"}]'::jsonb, 'c', 'ترتيب الآيات: وَالتِّينِ وَالزَّيْتُونِ، ثمّ وَطُورِ سِينِينَ، ثمّ وَهَٰذَا الْبَلَدِ الْأَمِينِ. الخطأ الشائع تقديمُ ذكر البلد الأمين على التين والزيتون.', 1)
