INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ec3f022-203d-5008-8aae-937c37c832c0', 'e0f50c36-a3f1-5492-8c46-184a29ee5a84', '«أجرٌ غير ممنون» يعني ثوابًا ...', '[{"id":"a","text":"قليلًا وينتهي سريعًا"},{"id":"b","text":"عظيمًا دائمًا لا ينقطع"},{"id":"c","text":"للكافرين فقط"},{"id":"d","text":"لا يأتي أبدًا"}]'::jsonb, 'b', 'أجرٌ غير ممنون أي ثوابٌ عظيمٌ دائمٌ لا ينقطع، أعدّه الله لمن آمن وعمل الصالحات.', 5)
