INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f2a04f2-562b-5c52-b5a2-9b25f01bcc72', 'e0f50c36-a3f1-5492-8c46-184a29ee5a84', 'ختمت السورة بأنّ الله هو ...', '[{"id":"a","text":"أضعفُ الحاكمين"},{"id":"b","text":"مثلُ سائر الحاكمين"},{"id":"c","text":"لا يحكم بين الناس"},{"id":"d","text":"أحكمُ الحاكمين وأعدلُهم"}]'::jsonb, 'd', 'قال الله: أَلَيْسَ اللَّهُ بِأَحْكَمِ الْحَاكِمِينَ، فالله هو أحكمُ الحاكمين وأعدلُهم.', 6)
