INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e4102ea0-da3f-5870-b444-67a99d5f403c', 'cda282b0-19cc-5742-aae4-f54782cd905b', 'أرادَ تلميذٌ أن يتلو سورة التين. ما أوّلُ آيةٍ يقرؤها بعد البَسملة؟', '[{"id":"a","text":"وَالتِّينِ وَالزَّيْتُونِ"},{"id":"b","text":"وَطُورِ سِينِينَ"},{"id":"c","text":"لَقَدْ خَلَقْنَا الْإِنسَانَ"},{"id":"d","text":"أَلَيْسَ اللَّهُ بِأَحْكَمِ الْحَاكِمِينَ"}]'::jsonb, 'a', 'أوّل آيةٍ في سورة التين هي: وَالتِّينِ وَالزَّيْتُونِ. الخطأ الشائع البدءُ بآيةٍ من وسط السورة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b194fe5e-35df-5416-be2d-101e5d59b953', 'cda282b0-19cc-5742-aae4-f54782cd905b', 'قال تلميذٌ إنّ كلّ الناس يُرَدّون إلى أسفل سافلين. ما الصواب؟', '[{"id":"a","text":"كلامُه صحيحٌ تمامًا"},{"id":"b","text":"يُرَدّ المؤمنون وحدهم"},{"id":"c","text":"استثنى الله الذين آمنوا وعملوا الصالحات"},{"id":"d","text":"لا يُرَدّ أحدٌ أبدًا"}]'::jsonb, 'c', 'قال الله: إِلَّا الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ، فاستثناهم من الرَّدّ إلى أسفل سافلين. الخطأ الشائع تعميمُ الرَّدّ على الجميع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('66412188-0515-5099-a1de-e2bfff4f3c50', 'cda282b0-19cc-5742-aae4-f54782cd905b', 'لماذا أقسم الله بالتين والزيتون وطور سينين والبلد الأمين؟', '[{"id":"a","text":"لأنّها أماكنُ بعيدة"},{"id":"b","text":"لأنّها أشياءُ وأماكنُ مباركة"},{"id":"c","text":"لأنّها ثقيلةُ الوزن"},{"id":"d","text":"لا سبب لذلك"}]'::jsonb, 'b', 'أقسم الله بهذه الأشياء والأماكن لأنّها مباركة (التين والزيتون، وطور سيناء، ومكّة)، لِيُنبّهنا إلى أهمّيّة ما بعدها. الخطأ الشائع ظنّ أنّ القَسَم بلا معنى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b3847a3-d25d-5082-b377-be75f85d510d', 'cda282b0-19cc-5742-aae4-f54782cd905b', 'تلميذٌ يصلّي ويبرّ والديه ويصدُق في كلامه. أيُّ وصفٍ يناسبه من السورة؟', '[{"id":"a","text":"كفر وعصى"},{"id":"b","text":"أهملَ الصالحات"},{"id":"c","text":"لا أجرَ له"},{"id":"d","text":"آمنَ وعملَ الصالحات فله أجرٌ غير ممنون"}]'::jsonb, 'd', 'الصلاةُ وبرُّ الوالدين وصدقُ الكلام من الأعمال الصالحة، فهذا تلميذٌ آمنَ وعملَ الصالحات وله أجرٌ غير ممنون. الخطأ الشائع عدمُ عَدِّ هذه الأعمال من الصالحات.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27e47c2c-7d7b-5f0c-a266-f966400a9460', 'cda282b0-19cc-5742-aae4-f54782cd905b', 'ما العلاقة بين «أحسن تقويم» و«أسفل سافلين» في السورة؟', '[{"id":"a","text":"كلاهما يصف المؤمنين"},{"id":"b","text":"كلاهما بمعنًى واحد"},{"id":"c","text":"خلق الله الإنسان في أحسن صورة، فمن كفر رُدّ إلى أسفل سافلين"},{"id":"d","text":"لا علاقة بينهما"}]'::jsonb, 'c', 'خلق الله الإنسان في أحسن تقويم (أحسن صورة)، فمن كفر وعصى رُدَّ إلى أسفل سافلين، أمّا من آمن فله الأجر. الخطأ الشائع ظنّ أنّ الوصفين بمعنًى واحد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0cbaa813-4f0f-58bf-8665-9d944981c9c9', 'cda282b0-19cc-5742-aae4-f54782cd905b', '«أليس الله بأحكم الحاكمين» سؤالٌ يدلّ على أنّ الله ...', '[{"id":"a","text":"أعدلُ وأعلمُ من كلّ من يحكم"},{"id":"b","text":"يحكم كغيره من الناس"},{"id":"c","text":"لا يهتمّ بأعمال العباد"},{"id":"d","text":"يترك الظالم بلا حساب"}]'::jsonb, 'a', 'السؤال يدلّ على أنّ الله أحكمُ الحاكمين وأعدلُهم وأعلمُهم، يُجازي كلّ إنسانٍ بعمله بالعدل التامّ. الخطأ الشائع مساواةُ حكم الله بحكم البشر.', 6)
ON CONFLICT (id) DO UPDATE SET
