INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b8a8520-7587-5ce1-8a73-1052ccffe3a4', 'e8bebcc8-896b-526c-b9f8-cf1df0048180', 'في سورة الليل، مَن أعطى واتّقى وصدّق بالحُسنى، ماذا يفعل الله له؟', '[{"id":"a","text":"ييسّره لليُسرى، أي طريق الخير"},{"id":"b","text":"ييسّره للعُسرى"},{"id":"c","text":"يتركه بلا جزاء"},{"id":"d","text":"يُعطيه مالًا فقط"}]'::jsonb, 'a', 'قال الله: فَأَمَّا مَنْ أَعْطَىٰ وَاتَّقَىٰ. فمَن أعطى واتّقى ييسّره الله لليُسرى، أي يُسهّل له طريق الخير والجنّة.', 3)
