INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c809585-4baf-5dd8-92c9-4a057f8e4c3a', 'e8bebcc8-896b-526c-b9f8-cf1df0048180', 'كلتا سورتَي الليل والشمس نزلتا في مكّة، فهما سورتان ...', '[{"id":"a","text":"مدنيّتان"},{"id":"b","text":"من التوراة"},{"id":"c","text":"مكّيّتان"},{"id":"d","text":"ليستا من القرآن"}]'::jsonb, 'c', 'سورة الليل وسورة الشمس كلتاهما مكّيّة، أي نزلت على النبيّ ﷺ في مكّة المكرّمة.', 4)
