INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59557701-3942-552e-a68d-c6506a29a1b3', 'e8bebcc8-896b-526c-b9f8-cf1df0048180', 'في سورة الشمس، قال الله: قَدْ أَفْلَحَ مَن زَكَّاهَا. ما معنى «أفلح مَن زكّاها»؟', '[{"id":"a","text":"فاز مَن طهّر نفسه بالخير والطاعة"},{"id":"b","text":"خسِر مَن طهّر نفسه"},{"id":"c","text":"نام مَن تعب"},{"id":"d","text":"ربح مَن جمع المال"}]'::jsonb, 'a', 'معنى «قَدْ أَفْلَحَ مَن زَكَّاهَا» أنّه فاز ونجح مَن طهّر نفسه بالخير والطاعة وابتعد عن الشرّ.', 5)
