INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d87b3727-7f33-556e-a711-f0a662022e51', 'c7c29677-1a80-57d6-b514-66e3ee97a21a', 'أكمل أوّل آية من سورة الليل: وَاللَّيْلِ إِذَا ...', '[{"id":"a","text":"يَغْشَىٰ"},{"id":"b","text":"تَجَلَّىٰ"},{"id":"c","text":"سَجَىٰ"},{"id":"d","text":"اسْتَوَىٰ"}]'::jsonb, 'a', 'أوّل آية في سورة الليل هي: وَاللَّيْلِ إِذَا يَغْشَىٰ، أي حين يُغطّي الليل الدنيا بظلامه.', 1)
