INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30bb4a59-e020-57d9-8181-b071e068a1c0', 'c7c29677-1a80-57d6-b514-66e3ee97a21a', 'كم عدد آيات سورة الليل؟', '[{"id":"a","text":"5 آيات"},{"id":"b","text":"21 آية"},{"id":"c","text":"100 آية"},{"id":"d","text":"آية واحدة"}]'::jsonb, 'b', 'سورة الليل عدد آياتها 21 آية، وهي سورة مكّيّة من القرآن الكريم.', 3)
