INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7338f146-80e7-55f2-95b1-41395e9ba0ae', 'c7c29677-1a80-57d6-b514-66e3ee97a21a', 'في سورة الشمس، بأيّ مخلوقَين أقسم الله في أوّل آيتين؟', '[{"id":"a","text":"الشمس والقمر"},{"id":"b","text":"الجبل والبحر"},{"id":"c","text":"الشجر والمطر"},{"id":"d","text":"الطير والنمل"}]'::jsonb, 'a', 'قال الله: وَالشَّمْسِ وَضُحَاهَا، وَالْقَمَرِ إِذَا تَلَاهَا. فأقسم بالشمس ثمّ بالقمر الذي يأتي بعدها.', 5)
