INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18378201-efbe-5b2f-8323-144c76a3bec4', 'c7c29677-1a80-57d6-b514-66e3ee97a21a', 'في سورة الليل: مَن أعطى واتّقى ييسّره الله ...', '[{"id":"a","text":"للعُسرى"},{"id":"b","text":"للنوم"},{"id":"c","text":"لليُسرى"},{"id":"d","text":"للّعب"}]'::jsonb, 'c', 'قال الله: فَأَمَّا مَنْ أَعْطَىٰ وَاتَّقَىٰ. فمَن أعطى واتّقى ييسّره الله لليُسرى، أي طريق الخير.', 6)
