  ('243a526f-fc19-562f-9368-f8aad5ed4ef8', '988227e3-4aba-5df4-b2be-0b65e2b8b2de', 'education-islamique-3eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ سورتَي الليل والشمس', 3, 120, 30, 'boss', 'admin', 2)
