INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9e3b73f5-c746-5dc8-83be-49cf2d9fb5f9', '243a526f-fc19-562f-9368-f8aad5ed4ef8', 'في سورة الليل قال الله: إِنَّ سَعْيَكُمْ لَشَتَّىٰ. ما معنى «لَشَتَّىٰ»؟', '[{"id":"a","text":"أعمالكم كلّها واحدة"},{"id":"b","text":"أعمالكم مختلفة متفرّقة"},{"id":"c","text":"أعمالكم قليلة"},{"id":"d","text":"لا عمل لكم"}]'::jsonb, 'b', '«لَشَتَّىٰ» تعني مختلفة متفرّقة، فأعمال الناس ليست واحدة: منهم المُحسن ومنهم المُسيء. الخطأ الشائع ظنّ أنّها بمعنى متشابهة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('86763f82-339c-5c0e-bec5-76d879075b01', '243a526f-fc19-562f-9368-f8aad5ed4ef8', 'في سورة الليل: مَن بخِل واستغنى وكذّب، ماذا يفعل الله له؟', '[{"id":"a","text":"يُيسّره للعُسرى، أي طريق الصعوبة"},{"id":"b","text":"يُيسّره لليُسرى"},{"id":"c","text":"يُعطيه الجنّة مباشرة"},{"id":"d","text":"يزيده مالًا"}]'::jsonb, 'a', 'قال الله: وَأَمَّا مَنْ بَخِلَ وَاسْتَغْنَىٰ. فمَن بخِل وكذّب يُيسّره الله للعُسرى، أي طريق الصعوبة. الخطأ الشائع الخلط بين جزاء الكريم وجزاء البخيل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('10b56136-71b9-5b8d-aca5-664ffd966f62', '243a526f-fc19-562f-9368-f8aad5ed4ef8', 'في سورة الشمس: ما الفرق بين «زَكَّاهَا» و«دَسَّاهَا»؟', '[{"id":"a","text":"كلاهما بمعنى طهّر النفس"},{"id":"b","text":"كلاهما بمعنى أفسد النفس"},{"id":"c","text":"زكّاها: نام، ودسّاها: استيقظ"},{"id":"d","text":"زكّاها: طهّر نفسه، ودسّاها: أفسد نفسه"}]'::jsonb, 'd', '«زَكَّاهَا» معناها طهّر نفسه بالخير ففاز، و«دَسَّاهَا» معناها أفسد نفسه بالشرّ فخاب. الخطأ الشائع ظنّ أنّ الكلمتين بمعنى واحد.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf3737d1-60f7-5c01-8508-83549e2c597d', '243a526f-fc19-562f-9368-f8aad5ed4ef8', 'ذكرت سورة الشمس قومًا كذّبوا نبيّهم بسبب طغيانهم، فمَن هم؟', '[{"id":"a","text":"قوم نوح"},{"id":"b","text":"قوم لوط"},{"id":"c","text":"قوم ثمود"},{"id":"d","text":"قوم فرعون"}]'::jsonb, 'c', 'قال الله: كَذَّبَتْ ثَمُودُ بِطَغْوَاهَا. فقوم ثمود كذّبوا نبيّهم صالحًا عليه السلام. الخطأ الشائع الخلط بينهم وبين قوم نوح أو فرعون.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1794817e-5c60-56bb-9588-49c47d626d4e', '243a526f-fc19-562f-9368-f8aad5ed4ef8', 'أيُّ آيةٍ من هاتين تدلّك على أنّ السورة هي سورة الليل لا الشمس؟', '[{"id":"a","text":"وَالشَّمْسِ وَضُحَاهَا"},{"id":"b","text":"وَاللَّيْلِ إِذَا يَغْشَىٰ"},{"id":"c","text":"وَالْقَمَرِ إِذَا تَلَاهَا"},{"id":"d","text":"وَنَفْسٍ وَمَا سَوَّاهَا"}]'::jsonb, 'b', 'سورة الليل تبدأ بـ وَاللَّيْلِ إِذَا يَغْشَىٰ، أمّا الآيات الأخرى ففي سورة الشمس. الخطأ الشائع ظنّ أنّ ذكر الليل يكون في سورة الليل فقط، مع أنّ سورة الشمس فيها أيضًا «وَاللَّيْلِ إِذَا يَغْشَاهَا».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddf45e0e-ca0a-5747-8731-447d27d98f09', '243a526f-fc19-562f-9368-f8aad5ed4ef8', 'ما العِبرة التي نتعلّمها من قصّة قوم ثمود في سورة الشمس؟', '[{"id":"a","text":"أنّ الطغيان والتكذيب لا يضرّان"},{"id":"b","text":"أن نلعب كثيرًا"},{"id":"c","text":"أنّ المال أهمّ شيء"},{"id":"d","text":"أن نُطيع الله ورسوله ولا نطغى"}]'::jsonb, 'd', 'عاقب الله ثمود لمّا طغَوا وكذّبوا وعقروا الناقة، فنتعلّم أن نُطيع الله ورسوله ولا نطغى. الخطأ الشائع الظنّ أنّ المعصية تمرّ بلا عقاب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
