INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4a7428a-4510-5746-9583-84e53e2293b1', '29fb607a-4716-5256-9410-b710e69f693c', 'قال الله في سورة الشمس: قَدْ أَفْلَحَ مَن ...', '[{"id":"a","text":"دَسَّاهَا"},{"id":"b","text":"نَامَ"},{"id":"c","text":"بَخِلَ"},{"id":"d","text":"زَكَّاهَا"}]'::jsonb, 'd', 'قال الله: قَدْ أَفْلَحَ مَن زَكَّاهَا، أي فاز مَن طهّر نفسه بالخير والطاعة.', 4)
