  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de3a5949-a964-5846-bac6-6917aa4f6c73', '29fb607a-4716-5256-9410-b710e69f693c', 'النفس التي طهّرها صاحبها بالخير والطاعة، صاحبها ...', '[{"id":"a","text":"خاب وخسِر"},{"id":"b","text":"تعب بلا فائدة"},{"id":"c","text":"أفلح وفاز"},{"id":"d","text":"لا شيء يحدث له"}]'::jsonb, 'c', 'قال الله: قَدْ أَفْلَحَ مَن زَكَّاهَا، فمَن طهّر نفسه بالخير فقد أفلح وفاز برضا الله.', 5)
