  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a60bca6-46c4-5c63-b95d-6c61dcc4746d', '29fb607a-4716-5256-9410-b710e69f693c', 'في سورة الليل: العطاء والتقوى يفتحان للإنسان طريق ...', '[{"id":"a","text":"الخير واليُسرى"},{"id":"b","text":"الصعوبة والعُسرى"},{"id":"c","text":"النوم"},{"id":"d","text":"اللعب"}]'::jsonb, 'a', 'مَن أعطى واتّقى ييسّره الله لليُسرى، فالعطاء والتقوى يفتحان طريق الخير، أمّا البُخل فيفتح طريق العُسرى.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('c25b8349-414c-54d7-88c9-b19217f11b03', '988227e3-4aba-5df4-b2be-0b65e2b8b2de', 'education-islamique-3eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ سورتَي الليل والشمس', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
