INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a2042e1-6b9e-5851-a572-c03e555e140c', 'c25b8349-414c-54d7-88c9-b19217f11b03', 'طفلٌ كريمٌ يُعطي ويتّقي الله ويُحبّ الخير. على أيّ قِسمٍ من قِسمَي سورة الليل ينطبق؟', '[{"id":"a","text":"قِسم مَن بخِل واستغنى"},{"id":"b","text":"قِسم مَن كذّب بالحُسنى"},{"id":"c","text":"ليس من القِسمين"},{"id":"d","text":"قِسم مَن أعطى واتّقى"}]'::jsonb, 'd', 'قال الله: فَأَمَّا مَنْ أَعْطَىٰ وَاتَّقَىٰ. فالطفل الكريم المتّقي من قِسم مَن أعطى واتّقى، وييسّره الله لليُسرى.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a14f145-3564-57d3-aee0-45de3b4305db', 'c25b8349-414c-54d7-88c9-b19217f11b03', 'قال أحدهم: «سورة الشمس لا تذكر الليل أبدًا». هل هذا صحيح؟', '[{"id":"a","text":"خطأ، فيها: وَاللَّيْلِ إِذَا يَغْشَاهَا"},{"id":"b","text":"صحيح، لا ذكر للّيل فيها"},{"id":"c","text":"صحيح، الليل في سورة الليل فقط"},{"id":"d","text":"لا نعرف"}]'::jsonb, 'a', 'هذا خطأ؛ ففي سورة الشمس آية: وَاللَّيْلِ إِذَا يَغْشَاهَا. الخطأ الشائع ظنّ أنّ كلّ سورةٍ لا تذكر إلّا ما في اسمها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('812f6f36-522e-5e76-805b-e9c2ea08539b', 'c25b8349-414c-54d7-88c9-b19217f11b03', 'ما الذي فعله أشقى قوم ثمود فعصَوا به ربّهم كما في سورة الشمس؟', '[{"id":"a","text":"أطعموا الناقة"},{"id":"b","text":"سقَوا الناقة"},{"id":"c","text":"عقروا الناقة"},{"id":"d","text":"حرسوا الناقة"}]'::jsonb, 'c', 'أرسل الله إلى ثمود ناقةً آيةً، فعقرها أشقاهم (أي ذبحها ظلمًا) فعصَوا ربّهم فعاقبهم الله. الخطأ الشائع الظنّ أنّهم أحسنوا إليها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1150a04-95a6-59f4-a40a-aa610e3f33af', 'c25b8349-414c-54d7-88c9-b19217f11b03', 'طفلٌ بخيلٌ لا يُعطي شيئًا ويُكذّب بالخير. ماذا قالت سورة الليل عن جزائه؟', '[{"id":"a","text":"ييسّره الله لليُسرى"},{"id":"b","text":"يُيسّره الله للعُسرى"},{"id":"c","text":"يُعطيه الله الجنّة"},{"id":"d","text":"لا جزاء عليه"}]'::jsonb, 'b', 'قال الله: وَأَمَّا مَنْ بَخِلَ وَاسْتَغْنَىٰ. فالبخيل المكذّب يُيسّره الله للعُسرى، أي طريق الصعوبة. الخطأ الشائع الخلط بينه وبين جزاء الكريم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4125796c-4352-5dcd-8d66-fa45229a6c8d', 'c25b8349-414c-54d7-88c9-b19217f11b03', 'أراد تلميذٌ أن يحفظ أوّل آيتين من سورة الشمس بالترتيب الصحيح. ما هما؟', '[{"id":"a","text":"وَالْقَمَرِ إِذَا تَلَاهَا ثمّ وَالشَّمْسِ وَضُحَاهَا"},{"id":"b","text":"وَاللَّيْلِ إِذَا يَغْشَىٰ ثمّ وَالشَّمْسِ وَضُحَاهَا"},{"id":"c","text":"وَالنَّهَارِ إِذَا تَجَلَّىٰ ثمّ وَالْقَمَرِ"},{"id":"d","text":"وَالشَّمْسِ وَضُحَاهَا ثمّ وَالْقَمَرِ إِذَا تَلَاهَا"}]'::jsonb, 'd', 'الترتيب الصحيح: وَالشَّمْسِ وَضُحَاهَا (آية 1) ثمّ وَالْقَمَرِ إِذَا تَلَاهَا (آية 2). الخطأ الشائع تقديم القمر على الشمس أو خلطها ببداية سورة الليل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('176aee1e-ec6c-597c-a5b6-9bfad2040dea', 'c25b8349-414c-54d7-88c9-b19217f11b03', 'ما القاعدة الكبرى التي علّمتنا إيّاها سورة الشمس عن النفس؟', '[{"id":"a","text":"النفس لا تتغيّر أبدًا"},{"id":"b","text":"مَن زكّى نفسه أفلح، ومَن دسّاها خاب"},{"id":"c","text":"كلّ الناس يفوزون"},{"id":"d","text":"النفس لا علاقة لها بالعمل"}]'::jsonb, 'b', 'قال الله: قَدْ أَفْلَحَ مَن زَكَّاهَا، وَقَدْ خَابَ مَن دَسَّاهَا. فمَن طهّر نفسه بالخير فاز، ومَن أفسدها بالشرّ خسِر. الخطأ الشائع الظنّ أنّ النجاح لا يتعلّق بعمل الإنسان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

