INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('738f527f-f3f6-5158-b0ad-fa86bc1687e6', '7e675207-eb56-5dfa-a86e-3a41d4198af0', 'أوّل آية في سورة الليل هي ...', '[{"id":"a","text":"وَاللَّيْلِ إِذَا يَغْشَىٰ"},{"id":"b","text":"وَالشَّمْسِ وَضُحَاهَا"},{"id":"c","text":"وَالضُّحَىٰ"},{"id":"d","text":"أَلَمْ نَشْرَحْ لَكَ صَدْرَكَ"}]'::jsonb, 'a', 'أوّل آية في سورة الليل هي: وَاللَّيْلِ إِذَا يَغْشَىٰ، فأقسم الله بالليل حين يُغطّي الدنيا بظلامه.', 1)
