INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80a16469-1f5d-53df-aa16-8364a33fec84', '7e675207-eb56-5dfa-a86e-3a41d4198af0', 'كلتا سورتَي الليل والشمس سورتان ...', '[{"id":"a","text":"مدنيّتان طويلتان"},{"id":"b","text":"ليستا من القرآن"},{"id":"c","text":"من الأناشيد"},{"id":"d","text":"مكّيّتان من القرآن الكريم"}]'::jsonb, 'd', 'سورة الليل وسورة الشمس كلتاهما مكّيّة، نزلتا على النبيّ ﷺ في مكّة، وهما من القرآن الكريم.', 2)
