INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c963232-82fa-5531-a7c4-2ced490a21e6', '7e675207-eb56-5dfa-a86e-3a41d4198af0', 'في سورة الليل قال الله: إِنَّ سَعْيَكُمْ لَشَتَّىٰ، أي أنّ أعمال الناس ...', '[{"id":"a","text":"كلّها واحدة"},{"id":"b","text":"مختلفة متفرّقة"},{"id":"c","text":"قليلة جدًّا"},{"id":"d","text":"ممنوعة"}]'::jsonb, 'b', '«لَشَتَّىٰ» معناها مختلفة متفرّقة، فمن الناس مَن يُحسن ومنهم مَن يُسيء، ولكلٍّ جزاؤه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
