INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80a5cbd9-63bb-5596-9261-e3a92e04b7af', '7e675207-eb56-5dfa-a86e-3a41d4198af0', 'في سورة الشمس: مَن أفسد نفسه بالشرّ، قال الله إنّه ...', '[{"id":"a","text":"أفلح وفاز"},{"id":"b","text":"نام وارتاح"},{"id":"c","text":"خاب وخسِر"},{"id":"d","text":"ربح مالًا"}]'::jsonb, 'c', 'قال الله: وَقَدْ خَابَ مَن دَسَّاهَا، أي خسِر مَن أفسد نفسه بالشرّ وابتعد عن الخير.', 4)
