INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47c3ec71-4197-5c44-86ac-64a85a820942', '7e675207-eb56-5dfa-a86e-3a41d4198af0', 'لماذا عاقب الله قوم ثمود كما ذكرت سورة الشمس؟', '[{"id":"a","text":"لأنّهم طغَوا وكذّبوا نبيّهم وعقروا الناقة"},{"id":"b","text":"لأنّهم أطاعوا الله"},{"id":"c","text":"لأنّهم سقَوا الناقة"},{"id":"d","text":"بلا سبب"}]'::jsonb, 'a', 'كذّبت ثمود نبيّها صالحًا عليه السلام بطغيانها، وعقر أشقاها الناقة، فعاقبهم الله جميعًا بسبب طغيانهم وعصيانهم.', 5)
ON CONFLICT (id) DO UPDATE SET
