INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e23b1289-93fa-5b1d-94ce-ed2eb82f58b7', '7e675207-eb56-5dfa-a86e-3a41d4198af0', 'ما الدرس المشترك بين سورتَي الليل والشمس؟', '[{"id":"a","text":"أنّ الليل أفضل من النهار"},{"id":"b","text":"أنّ الشمس أكبر من القمر"},{"id":"c","text":"أنّ المال هو الأهمّ"},{"id":"d","text":"أنّ مَن عمل الخير وزكّى نفسه فاز، ومَن بخِل وأفسد نفسه خسِر"}]'::jsonb, 'd', 'السورتان تعلّماننا أنّ العمل الصالح والعطاء وتزكية النفس طريق الفوز، وأنّ البُخل والطغيان وإفساد النفس طريق الخسران.', 6)
