  ('9d9d6ebf-b908-5041-b927-68c55b54d8b2', '0b15d03b-95d5-5431-8ed9-9ea908eef231', 'education-islamique-3eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ الطهارة', 4, 300, 60, 'challenge', 'admin', 4)
