INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('70fe3560-3d54-5446-beee-9f9d6d216c3f', '9d9d6ebf-b908-5041-b927-68c55b54d8b2', 'أرادَ تلميذٌ أن يُصلّيَ فتوضّأ. ما الذي جعل صلاتَه صحيحةً من جهة الطهارة؟', '[{"id":"a","text":"أنّه نام قبلها"},{"id":"b","text":"أنّه تطهّر بالوضوء قبل الصلاة"},{"id":"c","text":"أنّه لبس ثيابًا جديدة"},{"id":"d","text":"أنّه أكل قبلها"}]'::jsonb, 'b', 'الوضوء شرطٌ لصحّة الصلاة، فبتطهّره قبلها صحّت صلاتُه من جهة الطهارة. الخطأ الشائع ظنُّ أنّ الثياب الجديدة تُغني عن الوضوء.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('39c00c25-e672-5731-85ca-abdb28a0de0d', '9d9d6ebf-b908-5041-b927-68c55b54d8b2', 'توضّأ تلميذٌ فغسل وجهه ويدَيه ورجلَيه ونسي أن يمسح رأسه. ما حُكمُ وضوئه؟', '[{"id":"a","text":"صحيحٌ لأنّ مسح الرأس سُنّة"},{"id":"b","text":"صحيحٌ كاملًا"},{"id":"c","text":"أفضلُ من غيره"},{"id":"d","text":"غيرُ صحيحٍ لأنّه ترك فريضة"}]'::jsonb, 'd', 'مسح الرأس فريضةٌ من فرائض الوضوء، وتركُ الفريضة يُبطل الوضوء. الخطأ الشائع عدُّ مسح الرأس سُنّةً يجوز تركها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f3327e1-7ad8-5fe8-9f2c-209d598646a6', '9d9d6ebf-b908-5041-b927-68c55b54d8b2', 'بدأ تلميذٌ وضوءه فغسل وجهه أوّلًا قبل أن يُمضمض ويغسل يدَيه إلى الكوعين. ما الخطأ؟', '[{"id":"a","text":"أخلَّ بترتيب الأداء العملي للوضوء"},{"id":"b","text":"لا خطأ، الترتيب لا يهمّ"},{"id":"c","text":"كان عليه أن يبدأ بالرجلين"},{"id":"d","text":"كان عليه أن يمسح الرأس أوّلًا"}]'::jsonb, 'a', 'الترتيب العملي: غسل اليدين إلى الكوعين، فالمضمضة، فالاستنشاق، ثمّ غسل الوجه. فقد قدّم الوجه على ما قبله. الخطأ الشائع الاستهانةُ بترتيب الخطوات.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('859bafbc-1b60-56b5-aff4-a37a3227f689', '9d9d6ebf-b908-5041-b927-68c55b54d8b2', 'خرج تلميذٌ في رحلةٍ إلى الصحراء فلم يجد ماءً وحضرت الصلاة. ما الأصحّ أن يفعل؟', '[{"id":"a","text":"يترك الصلاة حتّى يرجع"},{"id":"b","text":"يُصلّي دون أيّ طهارة"},{"id":"c","text":"يتيمّم بالصَّعيد الطاهر ثمّ يُصلّي"},{"id":"d","text":"ينتظر نزول المطر"}]'::jsonb, 'c', 'عند فقد الماء يتيمّم بالصَّعيد الطاهر ويُصلّي في وقتها. الخطأ الشائع تأجيلُ الصلاة عن وقتها بحجّة فقد الماء.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0e78f3ee-6af1-591f-bc08-f1d43b4f3f57', '9d9d6ebf-b908-5041-b927-68c55b54d8b2', 'تيمّمَ مريضٌ ثمّ شُفيَ ووجد الماء وقدِر على استعماله. ماذا يفعل للصلاة القادمة؟', '[{"id":"a","text":"يبقى على التيمّم دائمًا"},{"id":"b","text":"يُصلّي دون طهارة"},{"id":"c","text":"يتيمّم مرّةً أخرى احتياطًا"},{"id":"d","text":"يعود إلى الوضوء بالماء"}]'::jsonb, 'd', 'التيمّم بديلٌ عند العجز فقط، فإذا وُجد الماء وأمكن استعمالُه عُدنا إلى الوضوء. الخطأ الشائع البقاءُ على التيمّم بعد زوال العذر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9075d681-fa4e-56ed-82c3-300851bd2cdb', '9d9d6ebf-b908-5041-b927-68c55b54d8b2', 'أرادَ تلميذٌ أن يُتقن حركات التيمّم بالترتيب الصحيح. ما الترتيب؟', '[{"id":"a","text":"النيّة، ثمّ ضرب اليدين على الصَّعيد، فمسح الوجه، فمسح اليدين إلى المرفقين"},{"id":"b","text":"مسح الرجلين ثمّ الوجه"},{"id":"c","text":"غسل الوجه بالماء ثمّ مسح اليدين"},{"id":"d","text":"مسح اليدين أوّلًا ثمّ الوجه قبل النيّة"}]'::jsonb, 'a', 'التيمّم يبدأ بالنيّة، ثمّ ضربِ اليدين على الصَّعيد الطاهر، فمسحِ الوجه، فمسحِ اليدين إلى المرفقين. الخطأ الشائع تقديمُ مسح اليدين على الوجه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

