  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90fe97af-bdc1-53e0-86d1-e29a0366d2fe', '16ca4cc0-c1ea-5130-8e47-3f2c1c053da2', 'تلميذٌ رفعَ من الركوع فقال: «سبحان ربّي العظيم». ما الأصحُّ أن يقول في هذا الموضع؟', '[{"id":"a","text":"سبحان ربّي الأعلى"},{"id":"b","text":"سمع الله لمن حمده، ربّنا ولك الحمد"},{"id":"c","text":"الله أكبر فقط"},{"id":"d","text":"أعوذ بالله من الشيطان الرجيم"}]'::jsonb, 'b', 'عند الرفع من الركوع نقول: سمع الله لمن حمده، ربّنا ولك الحمد. الخطأ الشائع إعادةُ ذكر الركوع في موضع الرفع منه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
