  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6395197b-3314-521a-ad8a-fb919f8f93e5', '16ca4cc0-c1ea-5130-8e47-3f2c1c053da2', 'تلميذٌ يحفظ أوّل التشهّد. أيُّ هذه هو بدايتُه الصحيحة؟', '[{"id":"a","text":"بسم الله الرحمن الرحيم"},{"id":"b","text":"الحمد لله ربّ العالمين"},{"id":"c","text":"سبحان ربّي الأعلى"},{"id":"d","text":"التحيّاتُ لله، الزاكياتُ لله"}]'::jsonb, 'd', 'يبدأ التشهّدُ بقولنا: التحيّاتُ لله، الزاكياتُ لله، الطيّباتُ الصلواتُ لله... الخطأ الشائع الخلطُ بين التشهّد وفاتحة القراءة.', 5)
ON CONFLICT (id) DO UPDATE SET
