INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('908bca15-4534-57e8-83e7-685a6cf35bb2', '16ca4cc0-c1ea-5130-8e47-3f2c1c053da2', 'تلميذٌ أراد أن يُنهيَ صلاته بالسلام بالطريقة الصحيحة. كيف يفعل؟', '[{"id":"a","text":"يقول السلام عليكم ملتفتًا يمينًا ثمّ يسارًا"},{"id":"b","text":"يقوم بسرعةٍ دون سلام"},{"id":"c","text":"يلتفت إلى الخلف ويصمت"},{"id":"d","text":"يُكبّر تكبيرة الإحرام من جديد"}]'::jsonb, 'a', 'نُنهي الصلاة بالسلام: نقول السلام عليكم ونلتفت بالوجه يمينًا ثمّ يسارًا. الخطأ الشائع تركُ السلام أو القيامُ قبله.', 6)
