INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41666adc-5a26-54af-9330-4483dc49c403', 'c962cfcb-269c-5e1e-9e70-0af2c7c3a8c1', 'صلّى رجلٌ الجمعة، فهل يُصلّي الظهر بعدها؟', '[{"id":"a","text":"نعم، يُصلّي الظهر أيضًا"},{"id":"b","text":"لا، لأنّ الجمعة تحلّ محلّ الظهر"},{"id":"c","text":"يُصلّي الظهر مرّتين"},{"id":"d","text":"يُصلّي العصر بدل الظهر"}]'::jsonb, 'b', 'صلاة الجمعة تحلّ محلّ صلاة الظهر، فمن صلّاها لم يُصلِّ الظهر. الخطأ الشائع ظنُّ أنّ على المصلّي أن يُصلّيَ الظهر بعد الجمعة.', 1)
