INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ceb12d1-93f1-5b28-84e9-5e28b8cc6260', 'c962cfcb-269c-5e1e-9e70-0af2c7c3a8c1', 'ما الترتيب الصحيح لصلاة الجمعة؟', '[{"id":"a","text":"الصلاةُ أوّلًا ثمّ الخطبتان"},{"id":"b","text":"خطبةٌ واحدةٌ فقط ثمّ الصلاة"},{"id":"c","text":"الصلاةُ بلا خطبةٍ أصلًا"},{"id":"d","text":"الخطبتان أوّلًا ثمّ الصلاةُ ركعتين"}]'::jsonb, 'd', 'في الجمعة يُلقي الإمامُ الخطبتين أوّلًا، يجلسُ بينهما جلسةً قصيرة، ثمّ تُقامُ الصلاةُ ركعتين. الخطأ الشائع تقديمُ الصلاة على الخطبتين.', 2)
