INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6d39198-fac0-59d9-9852-c3ec6d59dd72', 'c962cfcb-269c-5e1e-9e70-0af2c7c3a8c1', 'ماذا نفعل أثناء خطبة الجمعة؟', '[{"id":"a","text":"نُنصتُ ولا نتكلّم"},{"id":"b","text":"نتحدّثُ مع من بجانبنا"},{"id":"c","text":"نخرجُ من المسجد"},{"id":"d","text":"ننامُ حتّى تنتهي"}]'::jsonb, 'a', 'من آداب الجمعة الإنصاتُ للخطبة وعدمُ الكلام أثناءها. الخطأ الشائع الانشغالُ بالحديث مع الجار أثناء الخطبة.', 3)
