INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63ce3985-7397-5cb0-ac75-6ace6bab4f31', 'c962cfcb-269c-5e1e-9e70-0af2c7c3a8c1', 'هل يُؤذَّن لصلاة العيد وتُقام كبقيّة الصلوات؟', '[{"id":"a","text":"نعم، لها أذانٌ وإقامة"},{"id":"b","text":"لها إقامةٌ بلا أذان"},{"id":"c","text":"لا أذانَ لها ولا إقامة"},{"id":"d","text":"لها أذانان"}]'::jsonb, 'c', 'صلاة العيدين لا أذانَ لها ولا إقامة، تختلفُ بذلك عن بقيّة الصلوات. الخطأ الشائع ظنُّ أنّ لها أذانًا كالظهر والعصر.', 4)
