INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b26f291-c1e4-50a2-ae60-bd5adce473bc', '9d0e2843-fc8b-5045-b793-0809ff000f6d', 'ذهب تلميذٌ إلى المسجد يوم الجمعة فاغتسلَ وتطيّبَ ولبسَ ثيابًا نظيفةً وبكّرَ. ماذا نقولُ عنه؟', '[{"id":"a","text":"راعى آدابَ يوم الجمعة"},{"id":"b","text":"أهملَ آدابَ الجمعة"},{"id":"c","text":"أخطأ في كلّ شيء"},{"id":"d","text":"كان عليه أن يتأخّر"}]'::jsonb, 'a', 'الاغتسالُ والتطيّبُ ولبسُ الثياب الحسنة والتبكيرُ كلّها من آداب يوم الجمعة، فهذا تلميذٌ راعى الآدابَ أحسنَ مراعاة.', 1)
