INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('93937386-853d-5173-a29c-2d98a6477bc4', '9d0e2843-fc8b-5045-b793-0809ff000f6d', 'تلميذٌ صلّى العيدَ ثمّ قام ليذهب قبل خطبة الإمام ظنًّا منه أنّ لا خطبةَ في العيد. ما الصواب؟', '[{"id":"a","text":"أصابَ، فلا خطبةَ في العيد"},{"id":"b","text":"الخطبةُ تكون قبل الصلاة"},{"id":"c","text":"في العيد خطبةٌ بعد الصلاة كان عليه أن يبقى لها"},{"id":"d","text":"الخطبةُ في وسط الصلاة"}]'::jsonb, 'c', 'في العيد خطبةٌ بعد الصلاة يُذكّرُ فيها الإمامُ بأحكام العيد، فكان عليه أن يبقى. الخطأ الشائع مغادرةُ المُصلّى قبل خطبة العيد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a5472e92-5948-5477-b9fe-8421a4f4eea9', '9d0e2843-fc8b-5045-b793-0809ff000f6d', 'سُئل تلميذٌ: «ما الفرق بين خطبة الجمعة وخطبة العيد في وقتهما؟» فأيُّ جوابٍ صحيح؟', '[{"id":"a","text":"كلتاهما بعد الصلاة"},{"id":"b","text":"خطبةُ الجمعة قبل الصلاة وخطبةُ العيد بعدها"},{"id":"c","text":"كلتاهما قبل الصلاة"},{"id":"d","text":"خطبةُ الجمعة بعد الصلاة وخطبةُ العيد قبلها"}]'::jsonb, 'b', 'خطبةُ الجمعة تكون قبل الصلاة، وخطبةُ العيد تكون بعد الصلاة. الخطأ الشائع توهّمُ أنّ ترتيب الخطبة واحدٌ في الجمعة والعيد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

