INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c60b7c79-92d6-5417-9703-013a0f837f30', 'd8b36707-2965-508a-aee6-a63da8230952', 'بدأ الإمامُ صلاة الجمعة. ماذا فعلَ قبل الركعتين مباشرةً؟', '[{"id":"a","text":"نام قليلًا"},{"id":"b","text":"وزّعَ الطعام"},{"id":"c","text":"لعبَ مع الأطفال"},{"id":"d","text":"ألقى خطبتين وجلسَ بينهما جلسةً قصيرة"}]'::jsonb, 'd', 'قبل ركعتَي الجمعة يُلقي الإمامُ خطبتين على المنبر، ويجلسُ بينهما جلسةً قصيرة، ثمّ تُقامُ الصلاة. الخطأ الشائع نسيانُ الجلسة القصيرة بين الخطبتين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('60311110-6121-57db-b15c-80dfb7f785c0', 'd8b36707-2965-508a-aee6-a63da8230952', 'أيُّ هذه من حكمة صلاة الجمعة وفوائدها؟', '[{"id":"a","text":"إضاعةُ الوقت"},{"id":"b","text":"اجتماعُ المسلمين والتعاونُ بينهم"},{"id":"c","text":"البقاءُ في البيت"},{"id":"d","text":"تركُ الصلاة"}]'::jsonb, 'b', 'من حكمة الجمعة اجتماعُ المسلمين والتعاونُ بينهم وأداءُ الفرض والتذكيرُ بالقيم. الخطأ الشائع عدُّ الاجتماع مجرّدَ عادةٍ بلا فائدة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f700754-65f4-50e2-b1d5-930f5dd615e1', 'd8b36707-2965-508a-aee6-a63da8230952', 'في أيّ شهرٍ يكون عيد الأضحى؟', '[{"id":"a","text":"في شهر ذي الحجّة"},{"id":"b","text":"في شهر شوّال"},{"id":"c","text":"في شهر رمضان"},{"id":"d","text":"في شهر رجب"}]'::jsonb, 'a', 'عيد الأضحى يكون في اليوم العاشر من شهر ذي الحجّة، أمّا عيد الفطر ففي غُرّة شوّال. الخطأ الشائع الخلطُ بين شهرَي العيدين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d6b3586-e746-5dee-9f3a-326ffd3c0c06', 'd8b36707-2965-508a-aee6-a63da8230952', 'كم عددُ التكبيرات في الركعة الثانية من صلاة العيد؟', '[{"id":"a","text":"6 تكبيرات"},{"id":"b","text":"تكبيرةٌ واحدة"},{"id":"c","text":"5 تكبيرات"},{"id":"d","text":"لا تكبيراتِ فيها"}]'::jsonb, 'c', 'في الركعة الثانية من صلاة العيد 5 تكبيرات، ثمّ الفاتحةُ والسورةُ جهرًا، ثمّ التشهّدُ والتسليم. الخطأ الشائع جعلُ عدد تكبيرات الثانية كالأولى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e4467c1-7305-5af3-a9e9-38f967083de0', 'd8b36707-2965-508a-aee6-a63da8230952', 'بمَ يُذكّرُ الإمامُ في خطبة عيد الأضحى؟', '[{"id":"a","text":"بأحكام الأُضحية"},{"id":"b","text":"بمواعيد المدرسة"},{"id":"c","text":"بأخبار السوق"},{"id":"d","text":"بقواعد اللعب"}]'::jsonb, 'a', 'في خطبة العيد يُذكّرُ الإمامُ بأحكام العيد: أحكامِ الأُضحية في عيد الأضحى، وأحكامِ زكاة الفطر في عيد الفطر. الخطأ الشائع ظنُّ أنّ خطبة العيد بلا موضوعٍ خاص.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8327fbc4-1121-5ad5-9432-aec4dd1b9472', 'd8b36707-2965-508a-aee6-a63da8230952', 'قارنَ تلميذٌ بين الجمعة والعيد في الأذان. ما الصواب؟', '[{"id":"a","text":"كلتاهما بلا أذان"},{"id":"b","text":"كلتاهما لهما أذانان"},{"id":"c","text":"العيدُ له أذانٌ والجمعةُ بلا أذان"},{"id":"d","text":"الجمعةُ يُؤذَّن لها والعيدُ لا أذانَ له"}]'::jsonb, 'd', 'صلاة الجمعة يُؤذَّن لها، أمّا صلاة العيد فلا أذانَ لها ولا إقامة. الخطأ الشائع توهّمُ أنّ العيدَ كالجمعة في الأذان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

